<changes>
  <change>
    <file>hooks/useLocalStorage.ts</file>
    <description>Import 'Dispatch' and 'SetStateAction' from 'react' to fix errors related to 'React' namespace not being found, and update type annotations accordingly.</description>
    <content><![CDATA[import { useState, useEffect, Dispatch, SetStateAction } from 'react';

function useLocalStorage<T,>(key: string, initialValue: T): [T, Dispatch<SetStateAction<T>>] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(error);
      return initialValue;
    }
  });

  // This effect re-syncs state with localStorage when the key changes (e.g., on login/logout).
  useEffect(() => {
    let newValue: T;
    try {
      const item = window.localStorage.getItem(key);
      if (item !== null) {
        newValue = JSON.parse(item);
      } else {
        newValue = initialValue;
        // If no item exists, persist the initial value to localStorage.
        window.localStorage.setItem(key, JSON.stringify(initialValue));
      }
    } catch (error) {
      console.error(`Error with localStorage key "${key}":`, error);
      newValue = initialValue;
    }
    setStoredValue(newValue);
  }, [key, initialValue]);


  const setValue: Dispatch<SetStateAction<T>> = (value) => {
    try {
      const valueToStore = value instanceof Function ? value(storedValue) : value;
      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    const handleStorageChange = (e: StorageEvent) => {
      if (e.key === key) {
        try {
          setStoredValue(e.newValue ? JSON.parse(e.newValue) : initialValue);
        } catch (error) {
          console.error(error);
        }
      }
    };
    window.addEventListener('storage', handleStorageChange);
    return () => {
      window.removeEventListener('storage', handleStorageChange);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [key]);

  return [storedValue, setValue];
}

export default useLocalStorage;]]></content>
