import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, NavLink } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import HomeScreen from './screens/HomeScreen';
import PropertyScreen from './screens/PropertyScreen';
import AccountScreen from './screens/AccountScreen';
import { UserIcon } from './components/Icons';
import { useAuth } from './contexts/AuthContext';

type Tab = 'home' | 'properties' | 'account';

function App() {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState<Tab>('home');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const handleTabClick = (tab: Tab) => {
    setActiveTab(tab);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const navItems = [
    { title: 'Home', path: '/', tab: 'home' },
    { title: 'Properties', path: '/properties', tab: 'properties' },
    { title: 'Account', path: '/account', tab: 'account' },
  ];

  const mobileNavItems = [
    { title: 'Home', path: '/', tab: 'home' },
    { title: 'Properties', path: '/properties', tab: 'properties' },
    { title: 'Account', path: '/account', tab: 'account', icon: <UserIcon className="w-6 h-6" /> },
  ];

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return <HomeScreen />;
      case 'properties':
        return <PropertyScreen />;
      case 'account':
        return <AccountScreen />;
      default:
        return <HomeScreen />;
    }
  };

  return (
    <Router>
      <div className="flex h-screen overflow-hidden">
        <aside className="hidden md:flex flex-col w-64 bg-gray-100 dark:bg-gray-800 shadow-md">
          <Sidebar
            navItems={navItems}
            activeTab={activeTab}
            handleTabClick={handleTabClick}
          />
        </aside>

        <main className="flex-1 overflow-x-hidden overflow-y-auto bg-gray-50 dark:bg-gray-900 transition-colors duration-300 md:ml-64 pb-20 md:pb-0">
          <div className="container mx-auto px-4 py-8">
            {renderContent()}
          </div>
        </main>

        <footer className="md:hidden bg-white fixed bottom-0 left-0 w-full z-10 shadow-md">
          <div className="flex justify-around items-center py-2">
            {mobileNavItems.map((item) => (
              <NavLink
                key={item.tab}
                to={item.path}
                className={`flex flex-col items-center justify-center p-2 rounded-md hover:bg-gray-200 transition-colors duration-200 ${activeTab === item.tab ? 'bg-gray-200' : ''}`}
                onClick={() => handleTabClick(item.tab)}
              >
                {item.icon}
                <span className="text-sm">{item.title}</span>
              </NavLink>
            ))}
          </div>
        </footer>
      </div>
    </Router>
  );
}

export default App;
