        doc.text(`Report Generated: ${new Date().toLocaleDateString()}`, 14, 30);

        const tableColumn = ["Month", "Category", "Bill Amt", "Paid Amt", "Balance", "Notes"];
        const tableRows: any[] = [];

        propertyPayments.forEach(p => {
