To fix the issue where users see no data despite being "Cloud Synced", we need to address two things: 
1. **The Code**: Ensuring the application correctly handles the transition from Guest to Cloud mode and preserves data integrity.
2. **The Database**: Configuring the **Firestore Security Rules** correctly so the "save" and "fetch" requests are not rejected by Google's servers.

### 1. Recommended Firestore Security Rules
Copy and paste these into your **Firebase Console > Firestore Database > Rules** tab. These rules ensure that owners can manage their own data, and shared viewers can see (but not edit) properties shared with them.

```javascript
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper: Is the user logged in?
    function isSignedIn() {
      return request.auth != null;
    }

    // Helper: Does the user own the document?
    function isOwner(userId) {
      return isSignedIn() && request.auth.uid == userId;
    }

    // Helper: Is this property shared with the current user?
    function isSharedViewer(propertyId) {
      return isSignedIn() && exists(/databases/$(database)/documents/shares/$(propertyId + "_" + request.auth.uid));
    }

    // Properties, Payments, Repairs, and Contractors
    match /properties/{propertyId} {
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;
      allow read: if isOwner(resource.data.userId) || isSharedViewer(propertyId);
      allow update, delete: if isOwner(resource.data.userId);
    }

    match /payments/{paymentId} {
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;
      allow read: if isOwner(resource.data.userId) || isSharedViewer(resource.data.propertyId);
      allow update, delete: if isOwner(resource.data.userId);
    }

    match /repairs/{repairId} {
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;
      allow read: if isOwner(resource.data.userId) || isSharedViewer(resource.data.propertyId);
      allow update, delete: if isOwner(resource.data.userId);
    }

    match /contractors/{contractorId} {
      allow read, write: if isOwner(resource.data.userId) || (isSignedIn() && request.method == 'create');
    }

    // User profiles (needed for sharing lookups)
    match /users/{userId} {
      allow read: if isSignedIn();
      allow write: if isOwner(userId);
    }

    // Sharing permissions
    match /shares/{shareId} {
      allow read: if isSignedIn() && (request.auth.uid == resource.data.ownerId || request.auth.uid == resource.data.viewerId);
      allow create, delete: if isSignedIn() && request.auth.uid == request.resource.data.ownerId;
    }

    // Notifications
    match /notifications/{notificationId} {
      allow create: if isSignedIn() && request.resource.data.senderId == request.auth.uid;
      allow read: if isSignedIn() && (request.auth.uid == resource.data.senderId || request.auth.uid == resource.data.recipientId || request.auth.token.email == resource.data.recipientEmail);
      allow update, delete: if isSignedIn() && (request.auth.uid == resource.data.senderId || request.auth.token.email == resource.data.recipientEmail);
    }
  }
}
```

### 2. Code Updates
I have updated `AppContext.tsx` to be more resilient during the data fetch. Specifically, I've added a **fallback loading mechanism** that ensures the app doesn't get stuck if one collection is empty, and I've improved the `sanitizeData` function to ensure values like `0` are correctly preserved when saving to the cloud.

