const AppContext = createContext<AppContextType | undefined>(undefined);

// Improved sanitization that preserves 0 values and booleans but removes undefined/null for Firestore
const sanitizeData = (data: any): any => {
  if (data === null || data === undefined) return null;
  if (Array.isArray(data)) {
    return data.map(sanitizeData).filter(v => v !== undefined);
  } else if (typeof data === 'object') {
    const sanitized: any = {};
    Object.entries(data).forEach(([key, value]) => {
      // Preserve 0, false, and empty strings, but skip undefined
      if (value !== undefined) {
        sanitized[key] = sanitizeData(value);
      }
    });
    return sanitized;
  }
  return data;
};

const GuestDataProvider: React.FC<{ user: User | null, children: React.ReactNode }> = ({ user, children }) => {
