    const addProperty = (p: Omit<Property, 'id' | 'userId'>) => setProperties(cur => [...cur, { ...p, id: crypto.randomUUID(), userId: 'guest_user' }]);
    const updateProperty = (updated: Property) => setProperties(cur => cur.map(p => p.id === updated.id ? updated : p));
    const deleteProperty = (id: string) => setProperties(cur => cur.filter(p => p.id !== id));
    const addPayment = (p: Omit<Payment, 'id' | 'userId'>) => setPayments(cur => [...cur, { ...p, id: crypto.randomUUID(), userId: 'guest_user' }]);
    const updatePayment = (updated: Payment) => setPayments(cur => cur.map(p => p.id === updated.id ? updated : p));
    const deletePayment = (id: string) => setPayments(cur => cur.filter(p => p.id !== id));
    const addRepair = (r: Omit<Repair, 'id' | 'userId'>) => setRepairs(cur => [...cur, { ...r, id: crypto.randomUUID(), userId: 'guest_user' }]);
    const updateRepair = (updated: Repair) => setRepairs(cur => cur.map(r => r.id === updated.id ? updated : r));
    const deleteRepair = (id: string) => setRepairs(cur => cur.filter(r => r.id !== id));
    const addContractor = (c: Omit<Contractor, 'id' | 'userId'>) => { const nc = { ...c, id: crypto.randomUUID(), userId: 'guest_user' }; setContractors(cur => [...cur, nc]); return nc; };
    const updateContractor = (updated: Contractor) => setContractors(cur => cur.map(c => c.id === updated.id ? updated : c));
    const addNotification = async (n: any) => { setNotifications(current => [...current, { ...n, id: crypto.randomUUID(), userId: 'guest_user', senderId: 'guest_user', senderName: 'Guest', senderEmail: 'guest@local.com', timestamp: new Date().toISOString(), isAcknowledged: false }]); };
    const updateNotification = (id: string, updates: Partial<Notification>) => setNotifications(current => current.map(n => n.id === id ? { ...n, ...updates } : n));
    const deleteNotification = (id: string) => setNotifications(current => current.filter(n => n.id !== id));

    const value = useMemo(() => ({ properties, payments, repairs, contractors, notifications, addProperty, updateProperty, deleteProperty, addPayment, updatePayment, deletePayment, addRepair, updateRepair, deleteRepair, addContractor, updateContractor, addNotification, updateNotification, deleteNotification, migrateGuestData: async () => {}, hasGuestData: properties.length > 0, clearGuestData: () => {}, isMigrating: false, isUserPropertyOwner: async () => true }), [properties, payments, repairs, contractors, notifications]);
    return <AppProviderLogic data={value} isLoading={false}>{children}</AppProviderLogic>;
};

const AuthenticatedDataProvider: React.FC<{ user: User, isReadOnly: boolean, activeDbOwner: DBOwner, children: React.ReactNode }> = ({ user, isReadOnly, activeDbOwner, children }) => {
    const [properties, setProperties] = useState<Property[]>([]);
    const [payments, setPayments] = useState<Payment[]>([]);
    const [repairs, setRepairs] = useState<Repair[]>([]);
    const [contractors, setContractors] = useState<Contractor[]>([]);
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isMigrating, setIsMigrating] = useState(false);
    const [hasGuestData, setHasGuestData] = useState(false);

    // Check local storage on mount
    useEffect(() => {
        const check = () => {
            const keys = Object.values(GUEST_KEYS);
            for (const key of keys) {
                const data = localStorage.getItem(key);
                if (data && data !== '[]') {
                    setHasGuestData(true);
                    return;
                }
            }
            setHasGuestData(false);
        };
        check();
    }, []);

    useEffect(() => {
        if (!db || !user) {
            setIsLoading(false);
            return;
        }

        setIsLoading(true);
        const unsubs: (() => void)[] = [];

        let collectionsLoaded = 0;
        const markLoaded = () => {
            collectionsLoaded++;
            if (collectionsLoaded >= 4) setIsLoading(false);
        };

        // Safety timeout to avoid infinite spinner if Firestore is slow or rules are misconfigured
        const timeout = setTimeout(() => setIsLoading(false), 3000);

        const targetUserId = isReadOnly ? activeDbOwner.id : user.id;

        // Fetch primary collections
        unsubs.push(db.collection('properties').where('userId', '==', targetUserId).onSnapshot(s => { setProperties(s.docs.map(d => ({id: d.id, ...d.data()}))); markLoaded(); }, () => markLoaded()));
        unsubs.push(db.collection('payments').where('userId', '==', targetUserId).onSnapshot(s => { setPayments(s.docs.map(d => ({id: d.id, ...d.data()}))); markLoaded(); }, () => markLoaded()));
        unsubs.push(db.collection('repairs').where('userId', '==', targetUserId).onSnapshot(s => { setRepairs(s.docs.map(d => ({id: d.id, ...d.data()}))); markLoaded(); }, () => markLoaded()));
        unsubs.push(db.collection('contractors').where('userId', '==', targetUserId).onSnapshot(s => { setContractors(s.docs.map(d => ({id: d.id, ...d.data()}))); markLoaded(); }, () => markLoaded()));

        // Fetch notifications (sent or received)
        unsubs.push(db.collection('notifications').where('recipientEmail', '==', user.email.toLowerCase()).onSnapshot(s => setNotifications(prev => [...prev.filter(n => n.recipientEmail !== user.email), ...s.docs.map(d => ({id: d.id, ...d.data()}))])));
        unsubs.push(db.collection('notifications').where('senderId', '==', user.id).onSnapshot(s => setNotifications(prev => [...prev.filter(n => n.senderId !== user.id), ...s.docs.map(d => ({id: d.id, ...d.data()}))])));

        return () => {
            clearTimeout(timeout);
            unsubs.forEach(u => u());
        };
    }, [user, isReadOnly, activeDbOwner]);

    const clearGuestData = useCallback(() => {
        Object.values(GUEST_KEYS).forEach(k => localStorage.removeItem(k));
        setHasGuestData(false);
    }, []);

    const migrateGuestData = async () => {
        if (!db || isReadOnly || !user) return;
        const localProps = JSON.parse(localStorage.getItem(GUEST_KEYS.props) || '[]');
        const localPayments = JSON.parse(localStorage.getItem(GUEST_KEYS.payments) || '[]');
        const localRepairs = JSON.parse(localStorage.getItem(GUEST_KEYS.repairs) || '[]');
        const localContractors = JSON.parse(localStorage.getItem(GUEST_KEYS.contractors) || '[]');

        if (localProps.length === 0 && localContractors.length === 0) {
            clearGuestData();
            return;
        }

        setIsMigrating(true);
        try {
            const propMap: Record<string, string> = {};
            const conMap: Record<string, string> = {};

            // 1. Migrate Contractors
            for (const c of localContractors) {
                const { id, userId, ...rest } = c;
                const ref = await db.collection('contractors').add(sanitizeData({ ...rest, userId: user.id }));
                conMap[id] = ref.id;
            }

            // 2. Migrate Properties
            for (const p of localProps) {
                const { id, userId, ...rest } = p;
                const ref = await db.collection('properties').add(sanitizeData({ ...rest, userId: user.id }));
                propMap[id] = ref.id;
            }

            // 3. Migrate Relational Data
            const batchPromises = [];
            for (const p of localPayments) {
                const { id, userId, propertyId, ...rest } = p;
                const cloudId = propMap[propertyId];
                if (cloudId) batchPromises.push(db.collection('payments').add(sanitizeData({ ...rest, propertyId: cloudId, userId: user.id })));
            }
            for (const r of localRepairs) {
                const { id, userId, propertyId, contractorId, ...rest } = r;
                const cloudId = propMap[propertyId];
                const cloudConId = contractorId ? conMap[contractorId] : null;
                if (cloudId) batchPromises.push(db.collection('repairs').add(sanitizeData({ ...rest, propertyId: cloudId, contractorId: cloudConId, userId: user.id })));
            }

            await Promise.all(batchPromises);
            clearGuestData();
            alert("Success! Your local data has been migrated to the Cloud.");
        } catch (e: any) {
            console.error("Migration error:", e);
            alert(`Migration failed: ${e.message || 'Unknown error'}`);
        } finally {
            setIsMigrating(false);
        }
    };

    const addProperty = (p: any) => !isReadOnly && db.collection('properties').add(sanitizeData({ ...p, userId: user.id }));
    const updateProperty = (up: any) => !isReadOnly && db.collection('properties').doc(up.id).set(sanitizeData(up), { merge: true });
    const deleteProperty = async (id: string) => {
        if(isReadOnly) return;
        const batch = db.batch();
        const pQuery = await db.collection('payments').where('propertyId', '==', id).get();
        pQuery.forEach((d: any) => batch.delete(d.ref));
        const rQuery = await db.collection('repairs').where('propertyId', '==', id).get();
        rQuery.forEach((d: any) => batch.delete(d.ref));
        batch.delete(db.collection('properties').doc(id));
        await batch.commit();
    };
    const addPayment = (p: any) => !isReadOnly && db.collection('payments').add(sanitizeData({ ...p, userId: user.id }));
    const updatePayment = (up: any) => !isReadOnly && db.collection('payments').doc(up.id).set(sanitizeData(up), { merge: true });
    const deletePayment = (id: string) => !isReadOnly && db.collection('payments').doc(id).delete();
    const addRepair = (r: any) => !isReadOnly && db.collection('repairs').add(sanitizeData({ ...r, userId: user.id }));
    const updateRepair = (ur: any) => !isReadOnly && db.collection('repairs').doc(ur.id).set(sanitizeData(ur), { merge: true });
    const deleteRepair = (id: string) => !isReadOnly && db.collection('repairs').doc(id).delete();
    const addContractor = (c: any) => { 
        const ref = db.collection('contractors').doc(); 
        if(!isReadOnly) ref.set(sanitizeData({ ...c, userId: user.id })); 
        return { ...c, id: ref.id, userId: user.id }; 
    };
    const updateContractor = (uc: any) => !isReadOnly && db.collection('contractors').doc(uc.id).set(sanitizeData(uc), { merge: true });
    const addNotification = async (n: any) => { await db.collection('notifications').add(sanitizeData({ ...n, userId: user.id, senderId: user.id, senderName: user.name, senderEmail: user.email, timestamp: new Date().toISOString(), isAcknowledged: false })); };
    const updateNotification = (id: string, updates: any) => db.collection('notifications').doc(id).update(sanitizeData(updates));
    const deleteNotification = (id: string) => db.collection('notifications').doc(id).delete();

    const value = useMemo(() => ({ properties, payments, repairs, contractors, notifications, addProperty, updateProperty, deleteProperty, addPayment, updatePayment, deletePayment, addRepair, updateRepair, deleteRepair, addContractor, updateContractor, addNotification, updateNotification, deleteNotification, getSharesByOwner: async () => { const snap = await db.collection('shares').where('ownerId', '==', user.id).get(); return snap.docs.map((d: any) => ({ id: d.id, ...d.data() })); }, findUserByEmail: async (email: string) => { const snap = await db.collection('users').where('email', '==', email.toLowerCase()).limit(1).get(); return snap.empty ? null : { id: snap.docs[0].id, ...snap.docs[0].data() } as User; }, addShare: async (s: any) => { await db.collection('shares').doc(`${s.propertyId}_${s.viewerId}`).set(s); }, deleteShare: async (id: string) => { await db.collection('shares').doc(id).delete(); }, migrateGuestData, clearGuestData, hasGuestData, isMigrating, isUserPropertyOwner: async () => properties.length > 0 }), [properties, payments, repairs, contractors, notifications, user?.id, isReadOnly, hasGuestData, isMigrating, isLoading]);

    return <AppProviderLogic data={value} isLoading={isLoading}>{children}</AppProviderLogic>;
};

const AppProviderLogic: React.FC<{data: any, isLoading: boolean, children: React.ReactNode}> = ({ data, isLoading, children }) => {
    const { properties, payments, repairs, contractors } = data;
    const getPropertyById = (id: string) => properties.find((p: Property) => p.id === id);
    const getContractorById = (id: string) => contractors.find((c: Contractor) => c.id === id);
    const getPaymentsForProperty = (propertyId: string) => payments.filter((p: Payment) => p.propertyId === propertyId);
    const getRepairsForProperty = (propertyId: string) => repairs.filter((r: Repair) => r.propertyId === propertyId);
    const searchProperties = (query: string) => { const lq = query.toLowerCase(); return properties.filter((p: Property) => p.name.toLowerCase().includes(lq) || p.address.toLowerCase().includes(lq)); };
    const getSiteHealthScore = (id: string) => { 
        const ps = getPaymentsForProperty(id); 
        const rs = getRepairsForProperty(id); 
        let s = 100; 
        if (ps.length === 0) return 75; 
        ps.forEach(p => { if (p.rentPaidAmount < p.rentBillAmount) s -= 10; }); 
        s -= rs.filter(r => r.status !== RepairStatus.COMPLETE).length * 5; 
        return Math.max(0, Math.min(100, s)); 
    };

    const value = useMemo(() => ({ ...data, isLoading, getPropertyById, getContractorById, getPaymentsForProperty, getRepairsForProperty, searchProperties, getSiteHealthScore }), [data, isLoading]);
    return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { authStatus, user, isReadOnly, activeDbOwner } = useAuth();
    if (authStatus === 'authenticated' && user && activeDbOwner) return <AuthenticatedDataProvider user={user} isReadOnly={isReadOnly} activeDbOwner={activeDbOwner}>{children}</AuthenticatedDataProvider>;
    if (authStatus === 'guest') return <GuestDataProvider user={user}>{children}</GuestDataProvider>;
    const ld = { properties: [], payments: [], repairs: [], contractors: [], notifications: [], migrateGuestData: async() => {}, hasGuestData: false, clearGuestData: () => {}, isMigrating: false };
    return <AppProviderLogic data={ld} isLoading={authStatus === 'loading'}>{children}</AppProviderLogic>;
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (context === undefined) throw new Error('useAppContext must be used within an AppProvider');
  return context;
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { useAppContext } from '../contexts/AppContext';
import { Property, Tenant, Payment, RepairStatus, Repair } from '../types';
import Card, { CardContent, CardHeader } from '../components/Card';
import { ArrowDownTrayIcon, ArrowUpTrayIcon, PencilSquareIcon, ShieldCheckIcon, CreditCardIcon } from '../components/Icons';
import Modal from '../components/Modal';
import { ReportFilter, EditTarget } from '../App';
import { MONTHS } from '../constants';
import { useAuth } from '../contexts/AuthContext';

// Declare jsPDF globally
declare const jspdf: any;

interface ReportItem { date: string; propertyName: string; tenantName?: string; type: 'Rent' | 'Utility' | 'Repair'; category: string; billAmount: number; paidAmount: number; balance: number; repairStatus?: RepairStatus; originalId: string; userId: string; }
interface CsvRow { Date: string; 'Property Name': string; Type: 'Rent' | 'Utility' | 'Repair'; Category: string; 'Bill Amount': number; 'Paid Amount': number; }
interface ImportPreview { validRecords: CsvRow[]; errors: { row: number; message: string }[]; }
interface ReportingScreenProps { initialFilter: ReportFilter | null; onFilterApplied: () => void; onEditItem: (target: EditTarget) => void; }

const ReportingScreen: React.FC<ReportingScreenProps> = ({ initialFilter, onFilterApplied, onEditItem }) => {
    const { properties, payments, repairs, addPayment, updatePayment, addRepair, deletePayment, deleteRepair } = useAppContext();
    const { isReadOnly, user } = useAuth();

    const [filters, setFilters] = useState({ 
        type: 'all', 
        propertyId: 'all', 
        tenantId: 'all', 
        startDate: '', 
        endDate: '', 
        status: (initialFilter?.status || 'all') as 'all' | 'collected' | 'outstanding', 
        repairStatus: (initialFilter?.repairStatus || 'all') as 'all' | 'open' | 'completed',
        reportMonth: new Date().getMonth() + 1,
        reportYear: new Date().getFullYear()
    });

    useEffect(() => { if (initialFilter) { setFilters(prev => ({ ...prev, status: initialFilter.status || 'all', repairStatus: initialFilter.repairStatus || 'all' })); onFilterApplied(); } }, [initialFilter, onFilterApplied]);

    const [isImportModalOpen, setIsImportModalOpen] = useState(false);
    const [importPreview, setImportPreview] = useState<ImportPreview | null>(null);
    const [isReconcileModalOpen, setIsReconcileModalOpen] = useState(false);
    const [duplicatePayments, setDuplicatePayments] = useState<Payment[][]>([]);
    const [duplicateRepairs, setDuplicateRepairs] = useState<Repair[][]>([]);
    const [selections, setSelections] = useState<Record<string, string>>({});
    const fileInputRef = useRef<HTMLInputElement>(null);

    const tenants = useMemo(() => properties.flatMap(p => p.tenants.map(t => ({...t, propertyName: p.name, propertyId: p.id}))), [properties]);

    const reportData = useMemo(() => { 
        const items: ReportItem[] = []; 
        payments.forEach(p => { 
            const property = properties.find(prop => prop.id === p.propertyId); 
            if (!property) return; 
            const tenantName = property.tenants.map(t => t.name).join(', ');
            items.push({ date: new Date(p.year, p.month - 1, 1).toISOString(), propertyName: property.name, tenantName, type: 'Rent', category: 'Rent', billAmount: p.rentBillAmount, paidAmount: p.rentPaidAmount, balance: p.rentBillAmount - p.rentPaidAmount, originalId: p.id, userId: p.userId }); 
            p.utilities.forEach(u => { items.push({ date: new Date(p.year, p.month - 1, 1).toISOString(), propertyName: property.name, tenantName, type: 'Utility', category: u.category, billAmount: u.billAmount, paidAmount: u.paidAmount, balance: u.billAmount - u.paidAmount, originalId: p.id, userId: p.userId }); }); 
        }); 
        repairs.forEach(r => { 
            const property = properties.find(prop => prop.id === r.propertyId); 
            if (!property) return; 
            const tenantName = property.tenants.map(t => t.name).join(', ');
            items.push({ date: r.requestDate, propertyName: property.name, tenantName, type: 'Repair', category: 'Repair', billAmount: r.cost, paidAmount: r.status === RepairStatus.COMPLETE ? r.cost : 0, balance: r.status === RepairStatus.COMPLETE ? 0 : r.cost, repairStatus: r.status, originalId: r.id, userId: r.userId }); 
        }); 

        return items.filter(item => { 
            if (filters.type !== 'all' && item.type !== filters.type) return false; 
            const property = properties.find(p => p.id === filters.propertyId);
            if (filters.propertyId !== 'all' && item.propertyName !== property?.name) return false; 
            if (filters.tenantId !== 'all') {
                const tenant = tenants.find(t => t.id === filters.tenantId);
                if (!tenant || item.propertyName !== tenant.propertyName) return false;
            }
            const itemDate = new Date(item.date); 
            if (filters.startDate && itemDate < new Date(filters.startDate)) return false; 
            if (filters.endDate && itemDate > new Date(filters.endDate)) return false; 
            if (filters.status === 'collected' && item.paidAmount <= 0) return false; 
            if (filters.status === 'outstanding' && item.balance <= 0) return false; 
            if (item.type === 'Repair') { 
                if (filters.repairStatus === 'open' && item.repairStatus === RepairStatus.COMPLETE) return false; 
                if (filters.repairStatus === 'completed' && item.repairStatus !== RepairStatus.COMPLETE) return false; 
            } else if (filters.repairStatus !== 'all') { return false; } 
            return true; 
        }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()); 
    }, [payments, repairs, properties, tenants, filters]);

    const totals = useMemo(() => reportData.reduce((acc, item) => { acc.billAmount += item.billAmount; acc.paidAmount += item.paidAmount; acc.balance += item.balance; return acc; }, { billAmount: 0, paidAmount: 0, balance: 0 }), [reportData]);

    const handleFilterChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => { 
        const { name, value } = e.target;
        setFilters(prev => ({...prev, [name]: (name === 'reportMonth' || name === 'reportYear') ? parseInt(value) : value})); 
    };

    const handleExport = () => { const headers = ['Date', 'Property Name', 'Type', 'Category', 'Bill Amount', 'Paid Amount', 'Balance']; const rows = reportData.map(item => [ new Date(item.date).toLocaleDateString(), `"${item.propertyName.replace(/"/g, '""')}"`, item.type, item.category, item.billAmount, item.paidAmount, item.balance ].join(',')); const csvContent = [headers.join(','), ...rows].join('\n'); const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' }); const link = document.createElement('a'); link.setAttribute('href', URL.createObjectURL(blob)); link.setAttribute('download', `pmpr_report_${new Date().toISOString().split('T')[0]}.csv`); document.body.appendChild(link); link.click(); document.body.removeChild(link); };

    const handleGenerateStatement = () => {
        if (filters.propertyId === 'all') {
            alert("Please select a specific Property to generate a statement.");
            return;
        }

        const selectedProperty = properties.find(p => p.id === filters.propertyId);
        if (!selectedProperty) return;

        const { jsPDF } = jspdf;
        const doc = new jsPDF();

        // Colors
        const primaryBlue = [51, 102, 204];

        // 1. Header Section
        doc.setFontSize(28);
        doc.setTextColor(...primaryBlue);
        doc.setFont('helvetica', 'bold');
        doc.text('STATEMENT', 140, 25);

        doc.setFontSize(12);
        doc.setTextColor(0, 0, 0);
        doc.text(user?.companyName || '[Rental Company]', 20, 25);
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(10);
        const addressLines = (user?.companyAddress || '[Street Address]\n[City, ST ZIP]').split('\n');
        addressLines.forEach((line, i) => doc.text(line, 20, 31 + (i * 5)));
        doc.text(`Phone: ${user?.phone || '000-000-0000'}`, 20, 31 + (addressLines.length * 5));

        // Statement Date & Customer ID Box
        doc.rect(140, 35, 55, 14); // Outer box
        doc.line(140, 42, 195, 42); // Middle line
        doc.line(170, 35, 170, 49); // Vertical line
        doc.setFontSize(9);
        doc.setFont('helvetica', 'bold');
        doc.text('Statement Date', 142, 40);
        doc.text('Customer ID', 142, 47);
        doc.setFont('helvetica', 'normal');
        doc.text(new Date().toLocaleDateString(), 172, 40);
        doc.text(`[${selectedProperty.id.substring(0, 6).toUpperCase()}]`, 172, 47);

        // 2. Billing & Property Info
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.text('Bill To:', 20, 65);
        doc.setFont('helvetica', 'normal');
        const mainTenant = selectedProperty.tenants[0];
        doc.text(mainTenant?.name || '[Customer Name]', 35, 65);
        doc.text(selectedProperty.address, 35, 71);
        doc.text(mainTenant?.phone || '[Phone]', 35, 77);

        doc.setFont('helvetica', 'bold');
        doc.text('Property', 110, 65);
        doc.setFont('helvetica', 'normal');
        doc.text(selectedProperty.address, 130, 65);
        doc.text('Contract From', 110, 77);
        doc.text(new Date(selectedProperty.leaseStart).toLocaleDateString(), 145, 77);
        doc.text('To', 170, 77);
        doc.text(new Date(selectedProperty.leaseEnd).toLocaleDateString(), 180, 77);

        // 3. Transactions Table
        doc.setFont('helvetica', 'bold');
        doc.text('Account Activity', 20, 95);

        // Logic: Get balance forward
        const prevPayments = payments.filter(p => 
            p.propertyId === selectedProperty.id && 
            (p.year < filters.reportYear || (p.year === filters.reportYear && p.month < filters.reportMonth))
        );
        const prevBilled = prevPayments.reduce((sum, p) => {
            let b = p.rentBillAmount + p.utilities.reduce((s, u) => s + u.billAmount, 0);
            return sum + b;
        }, 0);
        const prevPaid = prevPayments.reduce((sum, p) => {
            let pd = p.rentPaidAmount + p.utilities.reduce((s, u) => s + u.paidAmount, 0);
            return sum + pd;
        }, 0);
        const balanceForward = prevBilled - prevPaid;

        // Transactions for the current month
        const currentMonthTransactions: any[] = [];
        const monthPayment = payments.find(p => p.propertyId === selectedProperty.id && p.year === filters.reportYear && p.month === filters.reportMonth);

        if (monthPayment) {
            currentMonthTransactions.push([
                `${monthPayment.month}/1/${monthPayment.year.toString().slice(-2)}`,
                `INV ${monthPayment.id.substring(0,4).toUpperCase()}`,
                `Rent for ${MONTHS[monthPayment.month-1]} '${monthPayment.year.toString().slice(-2)}`,
                monthPayment.rentBillAmount.toFixed(2)
            ]);
            monthPayment.utilities.forEach(u => {
                if (u.billAmount > 0) {
                    currentMonthTransactions.push([
                        `${monthPayment.month}/1/${monthPayment.year.toString().slice(-2)}`,
                        '',
                        u.category,
                        u.billAmount.toFixed(2)
                    ]);
                }
            });
            if (monthPayment.rentPaidAmount > 0 || monthPayment.utilities.some(u => u.paidAmount > 0)) {
                const totalPaid = monthPayment.rentPaidAmount + monthPayment.utilities.reduce((s, u) => s + u.paidAmount, 0);
                currentMonthTransactions.push([
                    monthPayment.paymentDate ? new Date(monthPayment.paymentDate).toLocaleDateString() : '',
                    'PMT',
                    'Payment Received - Thank you',
                    `-${totalPaid.toFixed(2)}`
                ]);
            }
        }

        const tableBody = [
            ['', '', 'Balance Forward', balanceForward.toFixed(2)],
            ...currentMonthTransactions
        ];

        doc.autoTable({
            head: [['DATE', 'REF', 'DESCRIPTION', 'AMOUNT']],
            body: tableBody,
            startY: 100,
            theme: 'striped',
            headStyles: { fillColor: primaryBlue, textColor: [255, 255, 255] },
            columnStyles: { 3: { halign: 'right' } },
        });

        const finalY = (doc as any).lastAutoTable.finalY + 10;
        const currentTotalBilled = (monthPayment?.rentBillAmount || 0) + (monthPayment?.utilities.reduce((s, u) => s + u.billAmount, 0) || 0);
        const currentTotalPaid = (monthPayment?.rentPaidAmount || 0) + (monthPayment?.utilities.reduce((s, u) => s + u.paidAmount, 0) || 0);
        const totalDue = balanceForward + currentTotalBilled - currentTotalPaid;

        doc.setFont('helvetica', 'bold');
        doc.text('BALANCE', 140, finalY);
        doc.rect(160, finalY - 6, 35, 8, 'F', [220, 230, 250]);
        doc.setTextColor(0,0,0);
        doc.text('$', 162, finalY);
        doc.text(totalDue.toFixed(2), 193, finalY, { align: 'right' });

        doc.setFontSize(9);
        doc.setTextColor(50);
        doc.text('Please pay this remaining balance. Thank you.', 135, finalY + 8);

        // 4. Remittance Slip
        const footerY = 240;
        doc.setLineDash([2, 2]);
        doc.line(20, footerY - 10, 190, footerY - 10);
        doc.setLineDash([]);
        doc.setFontSize(8);
        doc.text('Please detach the remittance slip below and return it with your payment.', 20, footerY - 5);

        doc.setFontSize(11);
        doc.setTextColor(...primaryBlue);
        doc.text('REMITTANCE', 95, footerY + 5);

        doc.setFontSize(10);
        doc.setTextColor(0,0,0);
        doc.text('Please make checks payable to:', 20, footerY + 15);
        doc.text(user?.companyName || user?.name || '', 20, footerY + 21);
        addressLines.forEach((line, i) => doc.text(line, 20, footerY + 27 + (i * 5)));

        doc.text('STATEMENT DATE', 120, footerY + 15);
        doc.text(new Date().toLocaleDateString(), 170, footerY + 15);
        doc.text('CUSTOMER ID', 120, footerY + 21);
        doc.text(`[${selectedProperty.id.substring(0, 6).toUpperCase()}]`, 170, footerY + 21);

        doc.text('DUE DATE', 130, footerY + 35);
        doc.rect(155, footerY + 30, 40, 8);
        doc.text('UPON RECEIPT', 157, footerY + 35);

        doc.setFont('helvetica', 'bold');
        doc.text('BALANCE DUE', 123, footerY + 45);
        doc.rect(155, footerY + 40, 40, 8);
        doc.text('$', 157, footerY + 45);
        doc.text(totalDue.toFixed(2), 193, footerY + 45, { align: 'right' });

        doc.save(`statement_${selectedProperty.name.replace(/\s/g, '_')}_${MONTHS[filters.reportMonth-1]}.pdf`);
    };

    const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => { const file = event.target.files?.[0]; if (file) { const reader = new FileReader(); reader.onload = e => processCsv(e.target?.result as string); reader.readAsText(file); } if(fileInputRef.current) fileInputRef.current.value = ""; };
    const processCsv = (csvText: string) => { const lines = csvText.split(/\r\n|\n/).filter(line => line.trim()); const headers = lines[0].split(',').map(h => h.trim()); const preview: ImportPreview = { validRecords: [], errors: [] }; for (let i = 1; i < lines.length; i++) { const values = lines[i].split(','); const record = headers.reduce((obj: Record<string, any>, header, index) => { const value = values[index]?.trim(); if (header === 'Bill Amount' || header === 'Paid Amount') { obj[header] = Number(value) || 0; } else { obj[header] = value; } return obj; }, {}) as CsvRow; if (!properties.some(p => p.name === record['Property Name'])) { preview.errors.push({ row: i + 1, message: `Property "${record['Property Name']}" not found.` }); continue; } preview.validRecords.push(record); } setImportPreview(preview); setIsImportModalOpen(true); };
    const handleConfirmImport = () => { if (!importPreview) return; for (const record of importPreview.validRecords) { const property = properties.find(p => p.name === record['Property Name']); if (!property) continue; const date = new Date(record.Date); const year = date.getFullYear(); const month = date.getMonth() + 1; if (record.Type === 'Repair') { addRepair({ propertyId: property.id, description: record.Category, cost: Number(record['Bill Amount']), status: Number(record['Paid Amount']) > 0 ? RepairStatus.COMPLETE : RepairStatus.PENDING_REPAIRMEN, requestDate: date.toISOString() }); } else { const existing = payments.find(p => p.propertyId === property.id && p.year === year && p.month === month); if (existing) { const updated = { ...existing }; if (record.Type === 'Rent') { updated.rentBillAmount = Number(record['Bill Amount']); updated.rentPaidAmount = Number(record['Paid Amount']); } else { const util = updated.utilities.find(u => u.category === record.Category); if (util) { util.billAmount = Number(record['Bill Amount']); util.paidAmount = Number(record['Paid Amount']); } else { updated.utilities.push({ category: record.Category, billAmount: Number(record['Bill Amount']), paidAmount: Number(record['Paid Amount']) }); } } updatePayment(updated); } else { addPayment({ propertyId: property.id, year, month, rentBillAmount: record.Type === 'Rent' ? Number(record['Bill Amount']) : 0, rentPaidAmount: record.Type === 'Rent' ? Number(record['Paid Amount']) : 0, utilities: record.Type === 'Utility' ? [{ category: record.Category, billAmount: Number(record['Bill Amount']), paidAmount: Number(record['Paid Amount'])}] : [], }); } } } alert(`${importPreview.validRecords.length} records imported successfully.`); setIsImportModalOpen(false); setImportPreview(null); };

    const handleReconcile = () => {
        const paymentGroups = (Object.values(
            payments.reduce((acc: Record<string, Payment[]>, p) => {
                const key = `${p.propertyId}-${p.year}-${p.month}`;
                if (!acc[key]) acc[key] = [];
                acc[key].push(p);
                return acc;
            }, {})
        ) as Payment[][]).filter(group => group.length > 1);

        const repairGroups = (Object.values(
            repairs.reduce((acc: Record<string, Repair[]>, r) => {
                const key = `${r.propertyId}-${r.description}-${r.cost}-${new Date(
                    r.requestDate
                ).toLocaleDateString()}`;
                if (!acc[key]) acc[key] = [];
                acc[key].push(r);
                return acc;
            }, {})
        ) as Repair[][]).filter(group => group.length > 1);

        setDuplicatePayments(paymentGroups);
        setDuplicateRepairs(repairGroups);
        const initialSelections: Record<string, string> = {};
        paymentGroups.forEach((group, index) => {
            const best = group.sort(
                (a, b) => (b.paymentDate ? 1 : -1) - (a.paymentDate ? 1 : -1)
            )[0];
            initialSelections[`payment-group-${index}`] = best.id;
        });
        repairGroups.forEach((group, index) => {
            const best = group.sort(
                (a, b) => (b.completionDate ? 1 : -1) - (a.completionDate ? 1 : -1)
            )[0];
            initialSelections[`repair-group-${index}`] = best.id;
        });
        setSelections(initialSelections);
        setIsReconcileModalOpen(true);
    };

    const handleConfirmReconciliation = () => { 
        const recordsToDelete: {type: 'payment' | 'repair', id: string}[] = []; 
        duplicatePayments.forEach((group, index) => { 
            const keepId = selections[`payment-group-${index}`]; 
            group.forEach(p => { if (p.id !== keepId) recordsToDelete.push({type: 'payment', id: p.id}) }); 
        }); 
        duplicateRepairs.forEach((group, index) => { 
            const keepId = selections[`repair-group-${index}`]; 
            group.forEach(r => { if (r.id !== keepId) recordsToDelete.push({type: 'repair', id: r.id}) }); 
        }); 
        if (window.confirm(`Are you sure you want to delete ${recordsToDelete.length} duplicate record(s)?`)) { 
            recordsToDelete.forEach(record => { if (record.type === 'payment') deletePayment(record.id); else deleteRepair(record.id); }); 
            alert(`${recordsToDelete.length} records deleted.`); 
            setIsReconcileModalOpen(false); 
        } 
    };

    return (
        <Card>
            <CardHeader>
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                    <h2 className="text-2xl font-bold">Reporting</h2>
                    <div className="flex flex-wrap gap-2">
                        <button onClick={handleGenerateStatement} className="flex items-center gap-2 px-3 py-2 text-sm bg-blue-600 text-white border border-blue-600 rounded-md shadow-sm hover:bg-blue-700">
                            <CreditCardIcon className="w-4 h-4" /> 
                            Rental Statement
                        </button>
                        <button onClick={handleReconcile} disabled={isReadOnly} className="flex items-center gap-2 px-3 py-2 text-sm bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50 disabled:bg-gray-200">
                            <ShieldCheckIcon className="w-4 h-4 text-green-600" /> 
                            Reconcile
                        </button>
                        <button onClick={() => fileInputRef.current?.click()} disabled={isReadOnly} className="flex items-center gap-2 px-3 py-2 text-sm bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50 disabled:bg-gray-200">
                            <ArrowUpTrayIcon className="w-4 h-4" /> 
                            Import
                        </button>
                        <input type="file" ref={fileInputRef} onChange={handleFileSelect} accept=".csv" className="hidden"/>
                        <button onClick={handleExport} className="flex items-center gap-2 px-3 py-2 text-sm bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50">
                            <ArrowDownTrayIcon className="w-4 h-4" /> 
                            Export
                        </button>
                    </div>
                </div>
            </CardHeader>
            <CardContent>
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 mb-4 p-4 bg-slate-50 rounded-lg"> 
