                  {menuItems.map(item => (
                      <button key={item.tab} onClick={() => onNavigate(item.tab)} className="w-full flex justify-between items-center px-6 py-5 text-left hover:bg-blue-50 transition-colors group">
                         <div className="flex items-center gap-4">
